import React, { useState, useRef, useEffect, useMemo, useCallback } from "react";
import { createPortal } from "react-dom";
import ArrowDropDownIcon from "@mui/icons-material/ArrowDropDown";
import CheckCircleIcon from "@mui/icons-material/CheckCircle";
import PersonIcon from "@mui/icons-material/Person";
import WarningIcon from "@mui/icons-material/Warning";
import HourglassEmptyIcon from "@mui/icons-material/HourglassEmpty";
import AutorenewIcon from "@mui/icons-material/Autorenew";
import AssignmentIcon from "@mui/icons-material/Assignment";
import CheckCircleOutlineIcon from "@mui/icons-material/CheckCircleOutline";
import FlagIcon from "@mui/icons-material/Flag";
import AddIcon from "@mui/icons-material/Add";
import RemoveIcon from "@mui/icons-material/Remove";
import GroupIcon from "@mui/icons-material/Group";
import { Space3DURL } from "../../utility/initApp.js";
import LayersIcon from "@mui/icons-material/Layers";
import AssigneePopup from "../AssigneePopup";
import AttachFileIcon from "@mui/icons-material/AttachFile";
import ArrowUpwardIcon from "@mui/icons-material/ArrowUpward";
import Service from "../../api/service";
import { showSuccessToast, showErrorToast } from "../toasts/ToastNotification";
import DeliverablesDots from "../DeliverablesDots";
import {
  openGlobalDropdown,
  closeGlobalDropdown,
  isGlobalDropdownOpen,
  subscribeToDropdownChanges
} from "../../utility/dropdownState";

const getInitials = (name) => {
  if (!name) return "";
  const parts = name.trim().split(" ");
  const first = parts[0]?.charAt(0).toUpperCase() || "";
  const last =
    parts.length > 1 ? parts[parts.length - 1].charAt(0).toUpperCase() : "";
  return first + last;
};


const calculateTooltipSize = (text, fontSize = 12, padding = 10) => {
  const canvas = document.createElement("canvas");
  const context = canvas.getContext("2d");
  context.font = `${fontSize}px Arial`;
  const lines = text.split("\n");
  const maxWidth = Math.max(
    ...lines.map((line) => context.measureText(line).width)
  );
  const height = lines.length * (fontSize + 4);
  return { width: maxWidth + padding * 2, height: height + padding * 2 };
};




const RhombusNode = ({
  id,
  x,
  y,
  width = 320,
  height = 130,
  title = "",
  subtitle = "",
  isChild,
  startDate,
  dueDate,
  assignees: d = [],
  maturity = "",
  maturityDescription = "",
  status = "",
  statusDescription = "",
  containerRef,
  description = "",
  dragNode,
  hasChildren = false,
  isExpanded = false,
  onDoubleClick = null,
  onMouseDown,
  isInitial = false,
  hierarchyDepth = 0,
  objectId,
  totalFloat = 0,
  showCriticalPath = false,
  isInChain = false,
  onHighlightChain = null,
  opacity = 1,
  loading = false,
  forceResetHover = false,
  projectId,
  onAddDeliverables = null,
  onRefresh,
  onUpdateNode,
  onPromoteNode,
  nodeColor, // Standardized prop for background fill
  delayDays, // Calculated delay from NodeRenderer
  timelineMode,
  zoomRatio,
  chainRootId,
  exitedChainNodes,
}) => {
  // ---- Status & tooltip state ----
  const safeStatus = (status || "").toLowerCase().trim();
  const showWarningIcon =
    safeStatus === "late" || safeStatus === "delay" || safeStatus === "delayed";
  const nodeRef = useRef(null);
  const dropdownRef = useRef(null);
  const [hoverIndex, setHoverIndex] = useState(null);
  const [tooltip, setTooltip] = useState({
    visible: false,
    text: "",
    textNode: null,
    width: 0,
    height: 0,
    x: 0,
    y: 0,
  });
  const isChainRoot = chainRootId === id;
  const isExitDisabled = isInChain && chainRootId && !isChainRoot && exitedChainNodes?.has(id);
  const ENOVIA_BASE_URL = Space3DURL;

  const showLocalTooltip = (tooltipString, tooltipNode) => {
    const { width: tw, height: th } = calculateTooltipSize(tooltipString, 12, 10);
    setTooltip({
      visible: true,
      text: tooltipString,
      textNode: tooltipNode,
      width: tw,
      height: th,
      x: width - tw - 8,
      y: height + 8,
    });
  };

  const hideLocalTooltip = () => {
    setTooltip((t) => ({ ...t, visible: false }));
  };

  const [highlighted, setHighlighted] = useState(false);
  const [isThisDropdownOpen, setIsThisDropdownOpen] = useState(false);
  const [showAssigneePopup, setShowAssigneePopup] = useState(false);

  // ---- Hover reset logic ----
  useEffect(() => {
    setHighlighted(false);
    hideLocalTooltip();
  }, [isInChain]);

  useEffect(() => {
    if (forceResetHover) {
      setHighlighted(false);
      hideLocalTooltip();
    }
  }, [forceResetHover]);

  // Effect to sync with global dropdown state
  useEffect(() => {
    const updateLocalState = () => {
      setIsThisDropdownOpen(isGlobalDropdownOpen(id));
    };
    updateLocalState();
    return subscribeToDropdownChanges(updateLocalState);
  }, [id]);

  useEffect(() => {
    if (isThisDropdownOpen) {
      setHighlighted(false);
      hideLocalTooltip();
    }
  }, [isThisDropdownOpen]);

  useEffect(() => {
    return () => {
      setHighlighted(false);
      hideLocalTooltip();
    };
  }, []);

  // Global mousemove guard — hides tooltip if cursor leaves node boundary
  useEffect(() => {
    if (!tooltip.visible) return;
    const handleGlobalMove = (e) => {
      const rect = nodeRef.current?.getBoundingClientRect();
      if (!rect) return;
      if (
        e.clientX < rect.left ||
        e.clientX > rect.right ||
        e.clientY < rect.top ||
        e.clientY > rect.bottom
      ) {
        hideLocalTooltip();
        setHighlighted(false);
      }
    };
    document.addEventListener("mousemove", handleGlobalMove);
    return () => document.removeEventListener("mousemove", handleGlobalMove);
  }, [tooltip.visible]);

  const isCritical = showCriticalPath && totalFloat === 0;

  // ---- Stroke color (same behavior as rectangle) ----
  const rhombusStroke = useMemo(() => {
    if (highlighted && isInChain) return "#3B82F6";
    if (highlighted && isCritical) return "#EF4444";
    if (isInChain) return "#1A73E8";
    if (isCritical) return "#CC0000";
    return highlighted ? "#4285F4" : "#1b1b17";
  }, [highlighted, isInChain, isCritical]);

  // ---- Rhombus points ----
  const rhombusPoints = useMemo(() => {
    const cx = width / 2;
    const cy = height / 2;
    const rx = width / 2 - 1;
    const ry = height / 2 - 1;
    return [
      `${cx},${cy - ry}`,
      `${cx + rx},${cy}`,
      `${cx},${cy + ry}`,
      `${cx - rx},${cy}`,
    ].join(" ");
  }, [width, height]);

  // =========================
  // 🔁 SIZES & LAYOUT (UPDATED)
  // =========================
  const padding = 10;
  const iconSize = 18;
  const spacing = 10;
  const statusWidth = 70;
  const statusHeight = 28;
  const titleFontPx = 12;
  const subtitleFontPx = 12;
  const pillFontPx = 12;
  const initialsFontPx = 12;
  const RIGHT_SHIFT_X = 28;

  // Positions
  const titleY = padding + 60;
  const subtitleY = padding + 36;
  const rowY = padding + 86;

  const assigneeList = Array.isArray(d)
    ? d.filter((n) => n && n.trim())
    : d && d.trim()
      ? [d]
      : [];
  const hasAssignee = assigneeList.length > 0;
  const assigneeColor = hasAssignee ? "#075985" : "#B0B0B0";
  const assigneeInitials = hasAssignee ? getInitials(assigneeList[0]) : "";
  const isMultipleAssignees = assigneeList.length > 1;

  const getMaturityDisplay = (m) => {
    if (!m) return "No Status";
    const s = String(m).toLowerCase().trim();

    if (s === "late") return "Late";
    if (s === "delay" || s === "delayed") return "Delayed";
    if (s === "active") return "In Work";
    if (s === "create") return "Draft";
    if (s === "assign") return "To Do";

    if (s.includes("to do") || s.includes("todo")) return "To Do";
    if (s.includes("in work") || s.includes("in-work") || s === "inwork")
      return "In Work";
    if (s.includes("draft")) return "Draft";
    if (s.includes("in progress") || s.includes("inprogress"))
      return "In Progress";
    if (s.includes("review") || s.includes("in review")) return "In Review";
    if (s.includes("complete") || s.includes("completed") || s.includes("done"))
      return "Completed";
    if (s.includes("release") || s.includes("released")) return "Released";
    if (s.includes("late") || s.includes("delayed")) return "Delayed";

    return m
      .split(" ")
      .map((word) => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
      .join(" ");
  };

  const getMaturityColor = (m) => {
    if (!m) return "rgb(110,110,110)";
    const s = String(m).toLowerCase().trim();
    if (
      s === "active" ||
      s.includes("in work") ||
      s.includes("in-work") ||
      s.includes("inwork") ||
      s.includes("in progress")
    ) {
      return showWarningIcon ? "rgba(150, 59, 59, 1)" : "#FFFFFF";
    }
    if (s === "create" || s.includes("draft")) {
      return "rgb(120,120,120)";
    }
    if (s === "assign" || s.includes("to do") || s.includes("todo")) {
      return "rgb(110,110,110)";
    }
    if (s.includes("review")) {
      return "rgb(70,65,125)";
    }
    if (s.includes("complete") || s.includes("done")) {
      return "rgba(11, 139, 21, 1)";
    }
    if (s.includes("release")) {
      return "rgba(37, 165, 224, 1)";
    }
    if (s.includes("late") || s.includes("delay")) {
      return "rgba(150, 59, 59, 1)";
    }
    return "rgb(110,110,110)";
  };

  const displayMaturity = getMaturityDisplay(maturity);
  const maturityColor = getMaturityColor(maturity);

  const subtitleIconMap = {
    "Pending Approval": (
      <HourglassEmptyIcon style={{ fontSize: iconSize, color: "#F28C38" }} />
    ),
    Phase: <AutorenewIcon style={{ fontSize: iconSize, color: "#234A96" }} />,
    Milestone: <FlagIcon style={{ fontSize: iconSize, color: "#2E7D32" }} />,
    Completed: (
      <CheckCircleIcon style={{ fontSize: iconSize, color: "#2E7D32" }} />
    ),
    Task: <AssignmentIcon style={{ fontSize: iconSize, color: "#707070" }} />,
    Late: <WarningIcon style={{ fontSize: iconSize, color: "#D9534F" }} />,
    Delayed: <WarningIcon style={{ fontSize: iconSize, color: "#D9534F" }} />,
  };

  const subtitleIcon =
    subtitleIconMap[subtitle] || (
      <HourglassEmptyIcon style={{ fontSize: iconSize, color: "#707070" }} />
    );

  const openMenu = useCallback((e) => {
    e.stopPropagation();
    e.preventDefault();
    hideLocalTooltip();
    openGlobalDropdown(id);
  }, [id]);

  const closeMenu = useCallback(() => closeGlobalDropdown(id), [id]);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        closeMenu();
      }
    };
    if (isThisDropdownOpen) {
      document.addEventListener("mousedown", handleClickOutside);
    } else {
      document.removeEventListener("mousedown", handleClickOutside);
    }
    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
    };
  }, [isThisDropdownOpen, closeMenu]);



  return (
    <g
      ref={nodeRef}
      transform={`translate(${x}, ${y})`}
      opacity={opacity}
      onMouseDown={(e) => onMouseDown && onMouseDown(e)}
      onMouseEnter={() => {
        setHighlighted(true);
        const displayAssignee = hasAssignee
          ? assigneeList.join(", ")
          : "No Assignee";
        const tooltipString =
          `Title: ${title}\n` +
          `Type: ${subtitle}\n` +
          `Estimated Start Date: ${startDate || "—"}\n` +
          `Due Date: ${dueDate || "—"}\n` +
          `Assignee: ${displayAssignee}\n` +
          `Maturity: ${displayMaturity || "—"}`;

        const tooltipNode = (
          <>
            <strong>Title:</strong> {title} <br />
            <strong>Type:</strong> {subtitle} <br />
            <strong>Estimated Start Date:</strong> {startDate || "—"} <br />
            <strong>Due Date:</strong> {dueDate || "—"} <br />
            <strong>{isMultipleAssignees ? "Assignees:" : "Assignee:"}</strong>{" "}
            {hasAssignee ? assigneeList.join(", ") : "No Assignee"} <br />
            <strong>Maturity:</strong> {displayMaturity || "—"} <br />
            {delayDays > 0 && (
              <>
                <strong style={{ color: "#D9534F" }}>Delayed By:</strong> {delayDays} Days <br />
              </>
            )}
            {maturityDescription && (
              <>
                <strong>Maturity Description:</strong> {maturityDescription}
                <br />
              </>
            )}
            {description && (
              <>
                <strong>Description:</strong> {description}
              </>
            )}
          </>
        );
        showLocalTooltip(tooltipString, tooltipNode);
      }}
      onMouseMove={() => {
        if (!tooltip.visible) {
          setHighlighted(true);
          const displayAssignee = hasAssignee
            ? assigneeList.join(", ")
            : "No Assignee";
          const tooltipString =
            `Title: ${title}\n` +
            `Type: ${subtitle}\n` +
            `Estimated Start Date: ${startDate || "—"}\n` +
            `Due Date: ${dueDate || "—"}\n` +
            `Assignee: ${displayAssignee}\n` +
            `Maturity: ${displayMaturity || "—"}`;

          const tooltipNode = (
            <>
              <strong>Title:</strong> {title} <br />
              <strong>Type:</strong> {subtitle} <br />
              <strong>Estimated Start Date:</strong> {startDate || "—"} <br />
              <strong>Due Date:</strong> {dueDate || "—"} <br />
              <strong>{isMultipleAssignees ? "Assignees:" : "Assignee:"}</strong>{" "}
              {hasAssignee ? assigneeList.join(", ") : "No Assignee"} <br />
              <strong>Maturity:</strong> {displayMaturity || "—"} <br />
              {maturityDescription && (
                <>
                  <strong>Maturity Description:</strong> {maturityDescription}
                  <br />
                </>
              )}
              {description && (
                <>
                  <strong>Description:</strong> {description}
                </>
              )}
            </>
          );

          showLocalTooltip(tooltipString, tooltipNode);
        }
      }}
      onMouseLeave={() => {
        setHighlighted(false);
        hideLocalTooltip();
      }}
      style={{
        cursor: dragNode === id ? "grabbing" : "grab",
        userSelect: "none",
      }}
    >
      {/* RHOMBUS SHAPE */}
      <polygon
        points={rhombusPoints}
        fill={nodeColor || "#FFFFFF"}
        stroke={rhombusStroke}
        strokeWidth={isInChain || isCritical ? 3 : 1}
        vectorEffect="non-scaling-stroke"
        filter={
          isInChain && isCritical
            ? "url(#chainNodeElevation)"
            : isInChain
              ? "url(#chainNodeElevation)"
              : isCritical && highlighted
                ? "url(#criticalNodeGlow)"
                : highlighted
                  ? "url(#nodeHover)"
                  : "none"
        }
        style={{
          transition:
            highlighted && !isInChain
              ? "filter 0.3s ease, stroke-width 0.3s ease"
              : "none",
        }}
      />

      {/* TITLE ROW */}
      <g transform={`translate(${padding + RIGHT_SHIFT_X + 16}, ${titleY})`}>
        {/* Text */}
        <text
          x={0}
          y={0}
          fontSize={titleFontPx}
          fontWeight="600"
          fill="#234A96"
          fontFamily="Arial, sans-serif"
        >
          {title.length > 25 ? title.substring(0, 22) + "..." : title}
        </text>
      </g>


      {/* Dropdown (20px) */}
      <g
        ref={dropdownRef}
        transform={`translate(${width - 38}, 64)`}
        onClick={(e) => {
          e.stopPropagation();
          if (isThisDropdownOpen) closeMenu();
          else openMenu(e);
        }}
        style={{ cursor: "pointer" }}
      >
        <foreignObject width={20} height={20}>
          <ArrowDropDownIcon style={{ fontSize: 20, color: "#5A5A5A" }} />
        </foreignObject>
      </g>

      {/* Expand / Collapse Toggle */}
      {hasChildren && !timelineMode && (
        <g
          transform={`translate(${width - 9}, -6)`}
          onClick={(e) => {
            e.stopPropagation();
            if (onDoubleClick) onDoubleClick();
          }}
          style={{ cursor: "pointer" }}
        >
          <rect width="20" height="20" rx="4" ry="4" fill="#eee" stroke="#666" strokeWidth="1" />
          <foreignObject x="2" y="2" width="16" height="16">
            {isExpanded ? (
              <RemoveIcon style={{ fontSize: 16, color: "#555", width: "16px", height: "16px" }} />
            ) : (
              <AddIcon style={{ fontSize: 16, color: "#555", width: "16px", height: "16px" }} />
            )}
          </foreignObject>
        </g>
      )}

      {/* Dropdown Menu */}
      {isThisDropdownOpen &&
        dropdownRef.current &&
        createPortal(
          (() => {
            const rect = dropdownRef.current.getBoundingClientRect();
            const taskId = objectId || id;

            return (
              <div
                style={{
                  position: "fixed",
                  top: rect.top,
                  left: rect.right + 16,
                  width: 150,
                  background: "white",
                  border: "1px solid #C8C6B8",
                  borderRadius: "4px",
                  fontSize: "12px",
                  boxShadow: "0 4px 12px rgba(0,0,0,0.35)",
                  fontFamily: "Arial",
                  padding: "4px",
                  zIndex: 999999999,
                  pointerEvents: "auto",
                }}
                onClick={(e) => e.stopPropagation()}
              >
                <div
                  style={{
                    padding: 8,
                    display: "flex",
                    alignItems: "center",
                    cursor: "pointer",
                    backgroundColor: hoverIndex === 0 ? "#bbb8b88a" : "transparent",
                    borderRadius: 4,
                    transition: "background 0.2s ease",
                    borderBottom: "1px solid #ccc",
                  }}
                  onMouseEnter={() => setHoverIndex(0)}
                  onMouseLeave={() => setHoverIndex(null)}
                  onClick={(e) => {
                    e.stopPropagation();
                    window.open(
                      `${ENOVIA_BASE_URL}/common/emxNavigator.jsp?isPopup=false&objectId=${taskId}`,
                      "_blank"
                    );
                  }}
                >
                  <CheckCircleOutlineIcon style={{ fontSize: 16, marginRight: 6 }} />
                  Open
                </div>

                {/* Add Deliverables Option */}
                <div
                  style={{
                    padding: 8,
                    display: "flex",
                    alignItems: "center",
                    cursor: "pointer",
                    backgroundColor: hoverIndex === 10 ? "#bbb8b88a" : "transparent",
                    borderRadius: 4,
                    borderBottom: "1px solid #ccc",
                    transition: "background 0.2s ease",
                  }}
                  onMouseEnter={() => setHoverIndex(10)}
                  onMouseLeave={() => setHoverIndex(null)}
                  onClick={(e) => {
                    e.stopPropagation();
                    closeMenu();
                    if (onAddDeliverables) {
                      onAddDeliverables(taskId, title);
                    }
                  }}
                >
                  <AttachFileIcon style={{ fontSize: 16, marginRight: 6, color: "#1A73E8" }} />
                  Add Deliverables
                </div>

                {(hasChildren) && (
                  <div
                    style={{
                      padding: 8,
                      display: "flex",
                      alignItems: "center",
                      cursor: (isExitDisabled || timelineMode) ? "not-allowed" : "pointer",
                      opacity: (isExitDisabled || timelineMode) ? 0.4 : 1,
                      backgroundColor:
                        hoverIndex === 3 && !(isExitDisabled || timelineMode)
                          ? "#bbb8b88a"
                          : "transparent",
                      borderRadius: 4,
                      borderBottom: "1px solid #ccc",
                      transition: "background 0.2s ease",
                      pointerEvents: (isExitDisabled || timelineMode) ? "none" : "auto",
                    }}
                    onMouseEnter={() => !(isExitDisabled || timelineMode) && setHoverIndex(3)}
                    onMouseLeave={() => setHoverIndex(null)}
                    onDoubleClick={(e) => {
                      e.stopPropagation();
                      e.preventDefault();
                    }}
                    onClick={(e) => {
                      if (timelineMode) return;
                      e.stopPropagation();
                      e.preventDefault();

                      if (isExitDisabled) return;

                      if (onHighlightChain) {
                        if (isInChain) {
                          onHighlightChain(id, true);
                        } else {
                          onHighlightChain(id, false);
                        }
                      }

                      closeMenu();
                    }}
                    title={timelineMode ? "Layered view is disabled in Timeline Mode" : ""}
                  >
                    <LayersIcon
                      style={{
                        fontSize: 16,
                        marginRight: 6,
                        color: isInChain ? "#1A73E8" : "#234A96",
                      }}
                    />
                    {isInChain ? "Exit Layered View" : "Show Layered View"}
                  </div>
                )}

                {(() => {
                  const isCompleted = displayMaturity === "Completed" || displayMaturity === "Released";
                  return (
                    <div
                      style={{
                        padding: 8,
                        display: "flex",
                        alignItems: "center",
                        cursor: isCompleted ? "not-allowed" : "pointer",
                        backgroundColor: hoverIndex === 1 && !isCompleted ? "#bbb8b88a" : "transparent",
                        borderRadius: 4,
                        transition: "background 0.2s ease",
                        borderBottom: "1px solid #ccc",
                        opacity: isCompleted ? 0.5 : 1,
                      }}
                      onMouseEnter={() => !isCompleted && setHoverIndex(1)}
                      onMouseLeave={() => setHoverIndex(null)}
                      onClick={(e) => {
                        if (isCompleted) return;
                        e.stopPropagation();
                        closeMenu();
                        setShowAssigneePopup(true);
                      }}
                    >
                      <PersonIcon style={{ fontSize: 16, marginRight: 6 }} />
                      Change Assignee
                    </div>
                  );
                })()}

                {(() => {
                  const isPromoteDisabled = displayMaturity === "Completed" || displayMaturity === "Released" || subtitle === "Phase";
                  return (
                    <div
                      style={{
                        padding: 8,
                        display: "flex",
                        alignItems: "center",
                        cursor: isPromoteDisabled ? "not-allowed" : "pointer",
                        backgroundColor: hoverIndex === 2 && !isPromoteDisabled ? "#bbb8b88a" : "transparent",
                        borderRadius: 4,
                        transition: "background 0.2s ease",
                        opacity: isPromoteDisabled ? 0.5 : 1,
                      }}
                      onMouseEnter={() => !isPromoteDisabled && setHoverIndex(2)}
                      onMouseLeave={() => setHoverIndex(null)}
                      onClick={(e) => {
                        if (isPromoteDisabled) return;
                        e.stopPropagation();
                        const taskIdToPromote = objectId || id;
                        if (!taskIdToPromote) return;
                        // Calculate next state based on current maturity
                        const getNextState = (currentMaturity) => {
                          const s = String(currentMaturity || "").toLowerCase().trim();
                          if (s === "create" || s.includes("draft")) return "Assign";
                          if (s === "assign" || s.includes("to do") || s.includes("todo")) return "Active";
                          if (s === "active" || s.includes("in work") || s.includes("progress")) return "Review";
                          if (s.includes("review")) return "Complete";
                          return "Active"; // Fallback
                        };
                        const nextState = getNextState(maturity);

                        // TRUE Optimistic UI: Update immediately, revert on failure
                        closeMenu();
                        setHoverIndex(null);
                        setTooltip((t) => ({ ...t, visible: false }));

                        if (onPromoteNode) {
                          onPromoteNode(id, taskIdToPromote, nextState, maturity);
                        } else {
                          if (onUpdateNode) {
                            onUpdateNode(id, { maturity: nextState });
                          }
                          Service.EnoviaService()
                            .promoteTask(taskIdToPromote, nextState)
                            .then((res) => {
                              showSuccessToast("Task promoted successfully!");
                              // If no optimistic update is available, fallback to full refresh
                              if (!onUpdateNode && onRefresh) onRefresh();
                            })
                            .catch((err) => {
                              showErrorToast("Failed to promote task. Reverting state...");
                              // Revert optimistic update
                              if (onUpdateNode) {
                                onUpdateNode(id, { maturity: maturity });
                              }
                            });
                        }
                      }}
                    >
                      <ArrowUpwardIcon style={{ fontSize: 16, marginRight: 6 }} />
                      Promote
                    </div>
                  );
                })()}
              </div>
            );
          })(),
          document.body
        )}

      {/* SUBTITLE ROW */}
      <g transform={`translate(${width / 2 + 6}, ${subtitleY})`}>
        {/* Icon */}
        <foreignObject x={-(subtitle.length * subtitleFontPx) / 2 - iconSize - 4} y={-12} width={iconSize} height={iconSize}>
          <div
            xmlns="http://www.w3.org/1999/xhtml"
            style={{
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              width: "100%",
              height: "100%",
            }}
          >
            {subtitleIcon}
          </div>
        </foreignObject>

        {/* Text */}
        <text
          x={-(subtitle.length * subtitleFontPx) / 2}
          y={2}
          fontSize={subtitleFontPx}
          fill="#0f0e0e"
        >
          {subtitle}
        </text>
        <DeliverablesDots taskId={objectId || id} x={width / 2 - 60} y={2} setTooltip={setTooltip} zoomRatio={zoomRatio} />
      </g>


      {/* MATURITY PILL - Moved up and leftward to align with date */}
      <g
        transform={`translate(${padding + 50 + iconSize + spacing + 62},${rowY - 22}) scale(0.86)`}
        onMouseEnter={() => {
          const tooltipString = `Maturity: ${displayMaturity || "—"}\n${maturityDescription || ""}`;
          const tooltipNode = (
            <>
              <strong>Maturity:</strong> {displayMaturity || "—"} <br />
              {maturityDescription && (
                <>
                  <strong>Maturity Description:</strong> {maturityDescription}
                  <br />
                </>
              )}
            </>
          );
          showLocalTooltip(tooltipString, tooltipNode);
        }}
        onMouseLeave={hideLocalTooltip}
      >
        <rect
          width={statusWidth}
          height={statusHeight}
          rx={10}
          fill={maturityColor}
          stroke={maturityColor === "#FFFFFF" ? "#C8C6B8" : "none"}
          strokeWidth={1}
        />
        <text
          x={statusWidth / 2}
          y={statusHeight / 2 + 1}
          fontSize={pillFontPx}
          fontWeight="600"
          fill={maturityColor === "#FFFFFF" ? "#333333" : "white"}
          textAnchor="middle"
          dominantBaseline="middle"
          fontFamily="Arial, sans-serif"
        >
          {displayMaturity}
        </text>
      </g>

      {/* Original Bottom Row (Date) */}
      <g transform={`translate(${padding + 50}, ${rowY - 13})`}>
        {/* Due Date Label */}
        <text x={0} y={-6} fontSize="8" fill="#999" fontWeight="600" letterSpacing="0.5" fontFamily="Arial, sans-serif">DUE DATE</text>
        {/* Due Date (12px) */}
        <text
          x={0}
          y={7}
          fontSize={subtitleFontPx}
          fill="#333"
          fontFamily="Arial, sans-serif"
        >
          {dueDate}
        </text>
      </g>

      {/* ASSIGNEE ICON - Now at bottom-center of the node */}
      <g
        transform={`translate(${width / 2}, ${height - 27})`}
        onMouseEnter={() => {
          const displayAssignee =
            Array.isArray(d) && d.length > 0
              ? d.join(", ")
              : d && typeof d === "string" && d.trim()
                ? d
                : "No Assignee";
          const tooltipNode = (
            <>
              <strong>Assignee:</strong> {displayAssignee}
            </>
          );
          showLocalTooltip(`Assignee: ${displayAssignee}`, tooltipNode);
        }}
        onMouseLeave={hideLocalTooltip}
        style={{ cursor: "default" }}
      >
        {isMultipleAssignees ? (
          <foreignObject
            x={-iconSize / 2 - 4}
            y={-iconSize / 2 - 6}
            width={iconSize + 8}
            height={iconSize + 8}
          >
            <div
              xmlns="http://www.w3.org/1999/xhtml"
              style={{
                width: iconSize + 8,
                height: iconSize + 8,
                borderRadius: "50%",
                backgroundColor: "#075985",
                display: "flex",
                justifyContent: "center",
                alignItems: "center",
              }}
            >
              <GroupIcon style={{ fontSize: iconSize, color: "#fff" }} />
            </div>
          </foreignObject>
        ) : (
          <>
            <circle r={iconSize / 2 + 4} fill={assigneeColor} />
            {assigneeInitials && (
              <text
                x="0"
                y="4"
                fontSize={initialsFontPx}
                textAnchor="middle"
                fill="white"
                fontWeight="600"
                fontFamily="Arial, sans-serif"
              >
                {assigneeInitials}
              </text>
            )}
          </>
        )}
      </g>

      {/* Tooltip */}
      {!isThisDropdownOpen && !showAssigneePopup &&
        tooltip.visible &&
        createPortal(
          (() => {
            const nodeRect = nodeRef.current?.getBoundingClientRect() || {
              top: 0, left: 0, bottom: 0, right: 0,
            };
            const vw = window.innerWidth;
            const vh = window.innerHeight;
            const MARGIN = 8;
            const spaceBelow = vh - nodeRect.bottom;
            const tooltipTop = spaceBelow < tooltip.height + MARGIN
              ? Math.max(MARGIN, nodeRect.top - tooltip.height - 4)
              : nodeRect.bottom + 4;
            const rawLeft = nodeRect.right - tooltip.width;
            const tooltipLeft = Math.max(MARGIN, Math.min(rawLeft, vw - tooltip.width - MARGIN));
            return (
              <div
                style={{
                  position: "fixed",
                  top: tooltipTop,
                  left: tooltipLeft,
                  minWidth: tooltip.width,
                  background: "white",
                  border: "1px solid #363a3fff",
                  borderRadius: "8px",
                  padding: "8px",
                  fontSize: "12px",
                  color: "#202124",
                  whiteSpace: "pre-line",
                  boxShadow: "0 4px 12px rgba(0,0,0,0.15)",
                  pointerEvents: "none",
                  zIndex: 999999999,
                  lineHeight: "1.6",
                }}
              >
                {tooltip.textNode}
              </div>
            );
          })(),
          document.body
        )}
      {showAssigneePopup && (
        <AssigneePopup
          taskId={objectId || id}
          projectId={projectId}
          taskName={title}
          onClose={() => setShowAssigneePopup(false)}
          onUpdate={(newAssignees) => {
            if (onUpdateNode) {
              onUpdateNode(id, { assignees: newAssignees });
            }
          }}
        />
      )}
    </g>
  );
};

export default RhombusNode;