  OPERATION: SHAPES.RECTANGLE,
  PROCESS: SHAPES.RECTANGLE,
  STEP: SHAPES.RECTANGLE,
  "NEXT STEP": SHAPES.RECTANGLE,

  // ===== HEXAGON SUBTITLES (including MILESTONE/DECISION) =====
  MILESTONE: SHAPES.HEXAGON,
  "KEY MILESTONE": SHAPES.HEXAGON,
  "MAJOR MILESTONE": SHAPES.HEXAGON,
  DECISION: SHAPES.HEXAGON,
  "KEY DECISION": SHAPES.HEXAGON,
  "MAJOR DECISION": SHAPES.HEXAGON,
  "ARCHITECTURE DECISION": SHAPES.HEXAGON,
