  END: SHAPES.ELLIPSE,
  FINISH: SHAPES.ELLIPSE,
  FINAL: SHAPES.ELLIPSE,
  TERMINAL: SHAPES.ELLIPSE,
  COMPLETED: SHAPES.ELLIPSE,
  DONE: SHAPES.ELLIPSE,
  FINISHED: SHAPES.ELLIPSE,

  // ===== HEXAGON SHAPES =====
  DELIVERABLE: SHAPES.HEXAGON,
  DELIVERABLES: SHAPES.HEXAGON,
  OUTPUT: SHAPES.HEXAGON,
  OUTPUTS: SHAPES.HEXAGON,
  RESULT: SHAPES.HEXAGON,
  PRODUCT: SHAPES.HEXAGON,
  ARTIFACT: SHAPES.HEXAGON,
  REVIEW: SHAPES.HEXAGON,
  REVIEWS: SHAPES.HEXAGON,
