// Helper to format date
function formateDate(d) {
  if (!d) return "";
  const date = new Date(d);
  return date.toLocaleDateString("en-US", {
    month: "short",
    day: "2-digit",
    year: "numeric",
  });
}

// Clean maturity status names
function cleanMaturityState(stateStr) {
  if (!stateStr) return "";
  let clean = String(stateStr).trim();
  if (clean.includes(":")) {
    clean = clean.split(":").pop();
  }
  const lower = clean.toLowerCase();
  if (lower === "open") return "In Work";
  if (lower === "active") return "In Work";
  if (lower === "create") return "Draft";
  if (lower === "assign") return "To Do";
  return clean;
}

// Dynamic 3dplan URL resolution
export const get3DPlanURL = () => {
  return new Promise((resolve, reject) => {
    try {
      if (typeof window === "undefined" || !window.requirejs) {
        reject(new Error("window.requirejs is not available"));
        return;
      }
      window.requirejs(
        ["DS/i3DXCompassServices/i3DXCompassServices"],
        function (i3DXCompassServices) {
          i3DXCompassServices.getServiceUrl({
            serviceName: "3dplan",
            onComplete: function (url) {
              const resolvedUrl = typeof url === "string" ? url : (Array.isArray(url) ? (url[0]?.url || url[0]) : url);
              resolve(resolvedUrl);
            },
            onFailure: function (err) {
              console.error("Service 3dplan URL Error:", err);
              reject(err);
            },
          });
        }
      );
    } catch (error) {
      reject(error);
    }
  });
};

// Authenticated request via WAFData
const authenticatedRequest = (url, options = {}) => {
  return new Promise((resolve, reject) => {
    try {
      if (typeof window === "undefined" || !window.requirejs) {
        reject(new Error("window.requirejs is not available"));
        return;
      }
      window.requirejs(["DS/WAFData/WAFData"], function (WAFData) {
        WAFData.authenticatedRequest(url, {
          ...options,
          onComplete: function (data) {
            resolve(data);
          },
          onFailure: function (err) {
            reject(err);
          }
        });
      });
    } catch (error) {
      reject(error);
    }
  });
};

const getRequest = async (url) => {
  return authenticatedRequest(url, {
    method: "GET",
    type: "json"
  });
};

const postRequest = async (url, data) => {
  return authenticatedRequest(url, {
    method: "POST",
    type: "json",
    headers: {
      "Content-Type": "application/json",
      "X-Requested-With": "XMLHttpRequest"
    },
    data: JSON.stringify(data)
  });
};

// Main function to fetch all Team Project data and convert it
export async function loadTeamProject(projectId) {
  const planUrl = await get3DPlanURL();
  const rawId = projectId.startsWith("uuid:") ? projectId.replace("uuid:", "") : projectId;
  
  // 1. Fetch Project Details
  const projectUrl = `${planUrl}/v1/resources/uuid:${rawId}?$mask=dsplan:MVMask.WorkPackage.Basic`;
  const project = await getRequest(projectUrl);
  
  // 2. Fetch Tasks
  const tasksUrl = `${planUrl}/v1/invoke/dsxplan:getFirstLevelLeafTasks?$mask=dsplan:MVMask.Task.CollaborativeTask.Basic`;
  const tasksPayload = [
    {
      versionURI: "uuid:" + rawId,
      openTask: null,
      filter: "all",
      fromCompletionDate: new Date().toISOString()
    }
  ];
  const tasksResponse = await postRequest(tasksUrl, tasksPayload);
  const tasksList = tasksResponse?.member || [];
  
  // 3. Fetch Task Details (if tasks exist)
  const taskIds = tasksList.map(task => `<${task["@id"]}>`);
  let taskDetailsResponse = { member: [] };
  if (taskIds.length > 0) {
    const detailsUrl = `${planUrl}/v1/invoke/dsxplan:fetchIds?$mask=dsplan:MVMask.Task.Complex`;
    const detailsPayload = {
      ids: taskIds,
      checkCommunity: false
    };
    taskDetailsResponse = await postRequest(detailsUrl, detailsPayload);
  }
  const detailsList = taskDetailsResponse?.member || [];
  const detailsMap = {};
  detailsList.forEach(detail => {
    detailsMap[detail["@id"]] = detail;
  });
  
  // 4. Fetch Dependencies
  const depsUrl = `${planUrl}/v1/invoke/dsxplan:getAllConnectedDependencies`;
  const depsPayload = [
    `uuid:${rawId}`,
    {
      reset: true,
      dependencyType: "all",
      dependencyStatus: "all",
      dependencySource: "all",
      subprojectDependencies: true
    }
  ];
  const depsResponse = await postRequest(depsUrl, depsPayload);
  let dependencies = [];
  if (depsResponse && depsResponse["@value"]) {
    try {
      dependencies = JSON.parse(depsResponse["@value"]);
    } catch (e) {
      console.error("Failed to parse Team Project dependencies:", e);
    }
  }
  
  // 5. Convert to Diagram
  const nodes = [];
  const nodeById = {};
  const edges = [];
  
  const rootId = project["@id"] || `uuid:${rawId}`;
  const childrenIds = tasksList.map(t => t["@id"]);
  
  // Create root project node
  const rootNode = {
    id: rootId,
    title: project["dsxplan:label"] || "Team Project",
    subtitle: "Project",
    status: project["dsxplan:hasMaturity"] || "",
    maturity: cleanMaturityState(project["dsxplan:hasMaturity"]),
    assignees: [],
    dueDate: "",
    rawDueDate: "",
    rawActualFinishDate: "",
    startDate: "",
    width: 220,
    height: 100,
    raw: project,
    totalFloat: 0,
    parentId: null,
    childrenIds: childrenIds,
    hasChildren: childrenIds.length > 0,
    isInitial: true,
    hierarchyDepth: 0,
  };
  
  nodes.push(rootNode);
  nodeById[rootId] = rootNode;
  
  // Create task nodes
  tasksList.forEach(task => {
    const id = task["@id"];
    const detail = detailsMap[id] || {};
    
    // Parse owner/assignee
    const owner = detail["dskern:owner"];
    let assigneeName = "";
    if (owner) {
      const given = owner["foaf:givenName"]?.["@value"] || owner["foaf:givenName"] || "";
      const family = owner["foaf:familyName"]?.["@value"] || owner["foaf:familyName"] || "";
      assigneeName = `${given} ${family}`.trim();
    }
    
    const taskNode = {
      id: id,
      title: task["dsxplan:label"] || detail["dsxplan:label"] || "",
      subtitle: task["dsxplan:jsType"] || detail["dsxplan:jsType"] || "Task",
      status: task["dsxplan:hasMaturity"] || detail["dsxplan:hasMaturity"] || "",
      maturity: cleanMaturityState(task["dsxplan:hasMaturity"] || detail["dsxplan:hasMaturity"]),
      assignees: assigneeName ? [assigneeName] : [],
      dueDate: formateDate(detail["dsxplan:estimatedEndDate"] || task["dsxplan:estimatedEndDate"]),
      rawDueDate: detail["dsxplan:estimatedEndDate"] || task["dsxplan:estimatedEndDate"] || "",
      rawActualFinishDate: detail["dsxplan:actualEndDate"] || "",
      startDate: formateDate(detail["dsxplan:estimatedStartDate"]),
      width: 220,
      height: 100,
      raw: { ...task, ...detail },
      totalFloat: 0,
      parentId: rootId,
      childrenIds: [],
      hasChildren: false,
      isInitial: false,
      hierarchyDepth: 1,
    };
    
    nodes.push(taskNode);
    nodeById[id] = taskNode;
    
    // Add hierarchy edge
    edges.push({ from: rootId, to: id, type: "hierarchy" });
  });
  
  // Add dependency edges
  dependencies.forEach(dep => {
    const fromId = dep["dsxplan:from"]?.["@id"];
    const toId = dep["dsxplan:to"]?.["@id"];
    if (fromId && toId && nodeById[fromId] && nodeById[toId]) {
      edges.push({ from: fromId, to: toId, type: "dependency" });
    }
  });
  
  return { nodes, edges, nodeById };
}
