import React, { useState, useRef, useEffect, useMemo, useCallback } from "react";
import { createPortal } from "react-dom";
import ArrowDropDownIcon from "@mui/icons-material/ArrowDropDown";
import CheckCircleIcon from "@mui/icons-material/CheckCircle";
import PersonIcon from "@mui/icons-material/Person";
import WarningIcon from "@mui/icons-material/Warning";
import HourglassEmptyIcon from "@mui/icons-material/HourglassEmpty";
import AutorenewIcon from "@mui/icons-material/Autorenew";
import AssignmentIcon from "@mui/icons-material/Assignment";
import CheckCircleOutlineIcon from "@mui/icons-material/CheckCircleOutline";
import FlagIcon from "@mui/icons-material/Flag";
import AddIcon from "@mui/icons-material/Add";
import RemoveIcon from "@mui/icons-material/Remove";
import GroupIcon from "@mui/icons-material/Group";
import { Space3DURL } from "../../utility/initApp.js";
import LayersIcon from "@mui/icons-material/Layers";
import AssigneePopup from "../AssigneePopup";
import AttachFileIcon from "@mui/icons-material/AttachFile";
import ArrowUpwardIcon from "@mui/icons-material/ArrowUpward";
import Service from "../../api/service";
import { showSuccessToast, showErrorToast } from "../toasts/ToastNotification";
import DeliverablesDots from "../DeliverablesDots";
import {
  openGlobalDropdown,
  closeGlobalDropdown,
  isGlobalDropdownOpen,
  subscribeToDropdownChanges
} from "../../utility/dropdownState";

const getInitials = (name) => {
  if (!name) return "";
  const parts = name.trim().split(" ");
  const first = parts[0]?.charAt(0).toUpperCase() || "";
  const last =
    parts.length > 1 ? parts[parts.length - 1].charAt(0).toUpperCase() : "";
  return first + last;
};

const calculateTooltipSize = (text, fontSize = 12, padding = 10) => {
  const canvas = document.createElement("canvas");
  const context = canvas.getContext("2d");
  context.font = `${fontSize}px Arial`;
  const lines = text.split("\n");
  const maxWidth = Math.max(
    ...lines.map((line) => context.measureText(line).width)
  );
  const height = lines.length * (fontSize + 4);
  return { width: maxWidth + padding * 2, height: height + padding * 2 };
};

const ParallelogramNode = ({
  id,
  x,
  y,
  width = 260,
  height = 65,
  title = "",
  subtitle = "",
  isChild,
  startDate,
  dueDate,
  assignees: d = [],
  maturity = "",
  maturityDescription = "",
  status = "",
  statusDescription = "",
  containerRef,
  description = "",
  dragNode,
  hasChildren = false,
  isExpanded = false,
  onDoubleClick = null,
  onMouseDown,
  isInitial = false,
  hierarchyDepth = 0,
  objectId,
  totalFloat = 0,
  showCriticalPath = false,
  isInChain = false,
  onHighlightChain = null,
  opacity = 1,
  loading = false,
  forceResetHover = false,
  projectId,
  onRefresh,
  onUpdateNode,
  onPromoteNode,
  skewAngle = 10,
  onAddDeliverables = null,
  nodeColor,
  delayDays,
  timelineMode,
  zoomRatio,
}) => {
  const safeStatus = (status || "").toLowerCase().trim();
  const isLateOrDelayed =
    safeStatus === "late" || safeStatus === "delay" || safeStatus === "delayed";
  const maturityIcon = (() => {
    const s = String(maturity).toLowerCase().trim();
    if (s.includes("late") || s.includes("delay")) {
      return <WarningIcon style={{ fontSize: 14, color: "#D9534F" }} />;
    }
    return null;
  })();
  const nodeRef = useRef(null);
  const dropdownRef = useRef(null);
  const [hoverIndex, setHoverIndex] = useState(null);
  const [tooltip, setTooltip] = useState({
    visible: false,
    text: "",
    textNode: null,
    width: 0,
    height: 0,
    x: 0,
    y: 0,
  });
  const ENOVIA_BASE_URL = Space3DURL;

  const showLocalTooltip = (tooltipString, tooltipNode) => {
    const { width: tw, height: th } = calculateTooltipSize(tooltipString);
    setTooltip({
      visible: true,
      text: tooltipString,
      textNode: tooltipNode,
      width: tw,
      height: th,
      x: width - tw - 8,
      y: height + 8,
    });
  };

  const hideLocalTooltip = () => {
    setTooltip((t) => ({ ...t, visible: false }));
  };

  const [highlighted, setHighlighted] = useState(false);
  const [isThisDropdownOpen, setIsThisDropdownOpen] = useState(false);
  const [showAssigneePopup, setShowAssigneePopup] = useState(false);

  // Calculate skew offset for parallelogram shape
  const skewOffset = useMemo(() => {
    return Math.tan((skewAngle * Math.PI) / 180) * height;
  }, [skewAngle, height]);

  // ── Unified content boundary (all layout derived from these) ──────────
  const padding = 10;
  const iconSize = 18;
  const spacing = 6;
  const statusWidth = 72;
  const statusHeight = 26;

  // The usable left/right edges inside the parallelogram, accounting for skew
  const contentLeft = padding + skewOffset / 2;
  const contentRight = width - skewOffset / 2 - padding;
  const contentWidth = contentRight - contentLeft;

  // Vertical positions
  const rowSpacing = (height - padding * 2) / 3;   // ≈ 15px each gap
  const titleY = padding + rowSpacing * 0.55;    // row 1
  const subtitleY = padding + rowSpacing * 1.55;    // row 2
  const rowY = padding + rowSpacing * 2.55;    // row 3

  // Assignee circle radius
  const assigneeR = iconSize / 2 + 4;

  // Effect 1: Reset hover when chain status changes
  useEffect(() => {
    setHighlighted(false);
    hideLocalTooltip();
  }, [isInChain]);

  // Effect 2: Reset hover when forceResetHover prop changes
  useEffect(() => {
    if (forceResetHover) {
      setHighlighted(false);
      hideLocalTooltip();
    }
  }, [forceResetHover]);

  // Effect to sync with global dropdown state
  useEffect(() => {
    const updateLocalState = () => {
      setIsThisDropdownOpen(isGlobalDropdownOpen(id));
    };
    updateLocalState();
    return subscribeToDropdownChanges(updateLocalState);
  }, [id]);

  // Effect 3: Reset hover when menu opens
  useEffect(() => {
    if (isThisDropdownOpen) {
      setHighlighted(false);
      hideLocalTooltip();
    }
  }, [isThisDropdownOpen]);

  // Effect 4: Reset hover when component unmounts
  useEffect(() => {
    return () => {
      setHighlighted(false);
      hideLocalTooltip();
    };
  }, []);

  // Effect 5: Global mousemove guard
  useEffect(() => {
    if (!tooltip.visible) return;
    const handleGlobalMove = (e) => {
      const rect = nodeRef.current?.getBoundingClientRect();
      if (!rect) return;
      if (
        e.clientX < rect.left ||
        e.clientX > rect.right ||
        e.clientY < rect.top ||
        e.clientY > rect.bottom
      ) {
        hideLocalTooltip();
        setHighlighted(false);
      }
    };
    document.addEventListener("mousemove", handleGlobalMove);
    return () => document.removeEventListener("mousemove", handleGlobalMove);
  }, [tooltip.visible]);

  const isCritical = showCriticalPath && totalFloat === 0;

  const strokeColor = useMemo(() => {
    if (highlighted && isInChain) return "#3B82F6";
    if (highlighted && isCritical) return "#EF4444";
    if (isInChain) return "#1A73E8";
    if (isCritical) return "#CC0000";
    return highlighted ? "#4285F4" : "#1b1b17";
  }, [highlighted, isInChain, isCritical]);

  const fillColor = useMemo(() => {
    return nodeColor || "#FFFFFF";
  }, [nodeColor]);

  const assigneeList = Array.isArray(d)
    ? d.filter((n) => n && n.trim())
    : d && d.trim()
      ? [d]
      : [];
  const hasAssignee = assigneeList.length > 0;
  const assigneeColor = hasAssignee ? "#075985" : "#B0B0B0";
  const assigneeInitials = hasAssignee ? getInitials(assigneeList[0]) : "";
  const isMultipleAssignees = assigneeList.length > 1;

  const getMaturityDisplay = (m) => {
    if (!m) return "No Status";
    const s = String(m).toLowerCase().trim();
    const isLate = s.includes("late") || s.includes("delay");
    
    let display = m;
    if (s === "late") display = "Late";
    else if (s === "delay" || s === "delayed") display = "Delayed";
    else if (s === "active") display = "In Work";
    else if (s === "create") display = "Draft";
    else if (s === "assign") display = "To Do";
    else if (s.includes("to do") || s.includes("todo")) display = "To Do";
    else if (s.includes("in work") || s.includes("in-work") || s === "inwork") display = "In Work";
    else if (s.includes("draft")) display = "Draft";
    else if (s.includes("in progress") || s.includes("inprogress")) display = "In Progress";
    else if (s.includes("review") || s.includes("in review")) display = "In Review";
    else if (s.includes("complete") || s.includes("completed") || s.includes("done")) display = "Completed";
    else if (s.includes("release") || s.includes("released")) display = "Released";
    else if (s.includes("late") || s.includes("delayed")) display = "Delayed";
    else {
      display = m
        .split(" ")
        .map((word) => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
        .join(" ");
    }
    
    if (isLate) {
      display = "⚠ " + display;
    }
    return display;
  };

  const getMaturityColor = (m) => {
    if (!m) return "rgb(110,110,110)";
    const s = String(m).toLowerCase().trim();
    if (s === "active" || s.includes("in work") || s.includes("in-work") || s.includes("inwork") || s.includes("in progress")) {
      return isLateOrDelayed ? "rgba(150, 59, 59, 1)" : "#FFFFFF";
    }
    if (s === "create" || s.includes("draft")) return "rgb(120,120,120)";
    if (s === "assign" || s.includes("to do") || s.includes("todo")) return "rgb(110,110,110)";
    if (s.includes("review")) return "rgb(70,65,125)";
    if (s.includes("complete") || s.includes("done")) return "rgba(11, 139, 21, 1)";
    if (s.includes("release")) return "rgba(37, 165, 224, 1)";
    if (s.includes("late") || s.includes("delay")) return "rgba(150, 59, 59, 1)";
    return "rgb(110,110,110)";
  };

  const displayMaturity = getMaturityDisplay(maturity);
  const maturityColor = getMaturityColor(maturity);

  const subtitleIconMap = {
    "Pending Approval": <HourglassEmptyIcon style={{ fontSize: iconSize, color: "#F28C38" }} />,
    Phase: <AutorenewIcon style={{ fontSize: iconSize, color: "#234A96" }} />,
    Milestone: <FlagIcon style={{ fontSize: iconSize, color: "#2E7D32" }} />,
    Completed: <CheckCircleIcon style={{ fontSize: iconSize, color: "#2E7D32" }} />,
    Task: <AssignmentIcon style={{ fontSize: iconSize, color: "#707070" }} />,
    Late: <WarningIcon style={{ fontSize: iconSize, color: "#D9534F" }} />,
    Delayed: <WarningIcon style={{ fontSize: iconSize, color: "#D9534F" }} />,
  };

  const subtitleIcon = subtitleIconMap[subtitle] || (
    <HourglassEmptyIcon style={{ fontSize: iconSize, color: "#707070" }} />
  );

  const openMenu = useCallback((e) => {
    e.stopPropagation();
    e.preventDefault();
    hideLocalTooltip();
    openGlobalDropdown(id);
  }, [id]);

  const closeMenu = useCallback(() => closeGlobalDropdown(id), [id]);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        closeMenu();
      }
    };
    if (isThisDropdownOpen) {
      document.addEventListener("mousedown", handleClickOutside);
    } else {
      document.removeEventListener("mousedown", handleClickOutside);
    }
    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
    };
  }, [isThisDropdownOpen, closeMenu]);

  // Build tooltip content (shared between onMouseEnter and onMouseMove)
  const buildTooltip = () => {
    const displayAssignee = hasAssignee ? assigneeList.join(", ") : "No Assignee";
    const tooltipString =
      `Title: ${title}\n` +
      `Type: ${subtitle}\n` +
      `Estimated Start Date: ${startDate || "—"}\n` +
      `Due Date: ${dueDate || "—"}\n` +
      `Assignee: ${displayAssignee}\n` +
      `Maturity: ${displayMaturity || "—"}`;

    const tooltipNode = (
      <>
        <strong>Title:</strong> {title} <br />
        <strong>Type:</strong> {subtitle} <br />
        <strong>Estimated Start Date:</strong> {startDate || "—"} <br />
        <strong>Due Date:</strong> {dueDate || "—"} <br />
        <strong>{isMultipleAssignees ? "Assignees:" : "Assignee:"}</strong>{" "}
        {hasAssignee ? assigneeList.join(", ") : "No Assignee"} <br />
        <strong>Maturity:</strong> {displayMaturity || "—"} <br />
        {delayDays > 0 && (
          <>
            <strong style={{ color: "#D9534F" }}>Delayed By:</strong> {delayDays} Days <br />
          </>
        )}
        {maturityDescription && (
          <>
            <strong>Maturity Description:</strong> {maturityDescription}<br />
          </>
        )}
        {description && (
          <>
            <strong>Description:</strong> {description}
          </>
        )}
      </>
    );
    return { tooltipString, tooltipNode };
  };

  return (
    <g
      ref={nodeRef}
      transform={`translate(${x}, ${y})`}
      opacity={opacity}
      onMouseDown={(e) => onMouseDown && onMouseDown(e)}
      onMouseEnter={() => {
        setHighlighted(true);
        const { tooltipString, tooltipNode } = buildTooltip();
        showLocalTooltip(tooltipString, tooltipNode);
      }}
      onMouseMove={() => {
        if (!tooltip.visible) {
          setHighlighted(true);
          const { tooltipString, tooltipNode } = buildTooltip();
          showLocalTooltip(tooltipString, tooltipNode);
        }
      }}
      onMouseLeave={() => {
        setHighlighted(false);
        hideLocalTooltip();
      }}
      style={{
        cursor: dragNode === id ? "grabbing" : "grab",
        userSelect: "none",
      }}
    >
      {/* Parallelogram shape */}
      <path
        d={`M ${skewOffset},0 L ${width},0 L ${width - skewOffset},${height} L 0,${height} Z`}
        fill={fillColor}
        stroke={strokeColor}
        strokeWidth={isInChain || isCritical ? 3 : 1}
        filter={
          isInChain && isCritical
            ? "url(#chainNodeElevation)"
            : isInChain
              ? "url(#chainNodeElevation)"
              : isCritical && highlighted
                ? "url(#criticalNodeGlow)"
                : highlighted
                  ? "url(#nodeHover)"
                  : "none"
        }
        style={{
          transition:
            highlighted && !isInChain
              ? "filter 0.3s ease, stroke-width 0.3s ease"
              : "none",
        }}
      />

      {/* ── Title ── fills content area, leaves room for dropdown arrow */}
      <text
        x={contentLeft}
        y={titleY - 2}
        fontSize="12"
        fontWeight="600"
        fill="#234A96"
        fontFamily="Arial, sans-serif"
      >
        {title.length > 25 ? title.substring(0, 22) + "..." : title}
      </text>

      {/* ── Dropdown arrow — right-aligned inside content area ── */}
      <g
        ref={dropdownRef}
        transform={`translate(${contentRight - 18}, 10)`}
        onClick={(e) => {
          e.stopPropagation();
          if (isThisDropdownOpen) closeMenu();
          else openMenu(e);
        }}
        style={{ cursor: "pointer" }}
      >
        <foreignObject width={20} height={20}>
          <ArrowDropDownIcon style={{ fontSize: 20, color: "#5A5A5A" }} />
        </foreignObject>
      </g>

      {/* ── Expand / Collapse Toggle ── */}
      {hasChildren && !timelineMode && (
        <g
          transform={`translate(${width - 9}, -6)`}
          onClick={(e) => {
            e.stopPropagation();
            if (onDoubleClick) onDoubleClick();
          }}
          style={{ cursor: "pointer" }}
        >
          <rect width="20" height="20" rx="4" ry="4" fill="#eee" stroke="#666" strokeWidth="1" />
          <foreignObject x="2" y="2" width="16" height="16">
            {isExpanded ? (
              <RemoveIcon style={{ fontSize: 16, color: "#555", width: "16px", height: "16px" }} />
            ) : (
              <AddIcon style={{ fontSize: 16, color: "#555", width: "16px", height: "16px" }} />
            )}
          </foreignObject>
        </g>
      )}

      {/* ── Dropdown Menu ── */}
      {isThisDropdownOpen &&
        dropdownRef.current &&
        createPortal(
          (() => {
            const rect = dropdownRef.current.getBoundingClientRect();
            const taskId = objectId || id;
            return (
              <div
                style={{
                  position: "fixed",
                  top: rect.top,
                  left: rect.right + 16,
                  width: 150,
                  background: "white",
                  border: "1px solid #C8C6B8",
                  borderRadius: "4px",
                  fontSize: "12px",
                  boxShadow: "0 4px 12px rgba(0,0,0,0.35)",
                  fontFamily: "Arial",
                  padding: "4px",
                  zIndex: 999999999,
                  pointerEvents: "auto",
                }}
                onClick={(e) => e.stopPropagation()}
              >
                <div
                  style={{
                    padding: 8, display: "flex", alignItems: "center", cursor: "pointer",
                    backgroundColor: hoverIndex === 0 ? "#bbb8b88a" : "transparent",
                    borderRadius: 4, transition: "background 0.2s ease", borderBottom: "1px solid #ccc",
                  }}
                  onMouseEnter={() => setHoverIndex(0)}
                  onMouseLeave={() => setHoverIndex(null)}
                  onClick={(e) => {
                    e.stopPropagation();
                    window.open(`${ENOVIA_BASE_URL}/common/emxNavigator.jsp?isPopup=false&objectId=${taskId}`, "_blank");
                  }}
                >
                  <CheckCircleOutlineIcon style={{ fontSize: 16, marginRight: 6 }} />
                  Open
                </div>

                <div
                  style={{
                    padding: 8, display: "flex", alignItems: "center", cursor: "pointer",
                    backgroundColor: hoverIndex === 10 ? "#bbb8b88a" : "transparent",
                    borderRadius: 4, transition: "background 0.2s ease", borderBottom: "1px solid #ccc",
                  }}
                  onMouseEnter={() => setHoverIndex(10)}
                  onMouseLeave={() => setHoverIndex(null)}
                  onClick={(e) => {
                    e.stopPropagation();
                    closeMenu();
                    if (onAddDeliverables) onAddDeliverables(taskId, title);
                  }}
                >
                  <AttachFileIcon style={{ fontSize: 16, marginRight: 6, color: "#1A73E8" }} />
                  Add Deliverables
                </div>

                {(hasChildren || isInChain) && (
                  <div
                    style={{
                      padding: 8,
                      display: "flex",
                      alignItems: "center",
                      cursor: timelineMode ? "not-allowed" : "pointer",
                      opacity: timelineMode ? 0.4 : 1,
                      backgroundColor:
                        hoverIndex === 3 && !timelineMode
                          ? "#bbb8b88a"
                          : "transparent",
                      borderRadius: 4,
                      borderBottom: "1px solid #ccc",
                      transition: "background 0.2s ease",
                      pointerEvents: timelineMode ? "none" : "auto",
                    }}
                    onMouseEnter={() => !timelineMode && setHoverIndex(3)}
                    onMouseLeave={() => setHoverIndex(null)}
                    onDoubleClick={(e) => {
                      e.stopPropagation();
                      e.preventDefault();
                    }}
                    onClick={(e) => {
                      if (timelineMode) return;
                      e.stopPropagation();
                      e.preventDefault();
                      if (onHighlightChain) {
                        if (isInChain) onHighlightChain(id, true);
                        else onHighlightChain(id, false);
                      }
                      closeMenu();
                    }}
                  >
                    <LayersIcon style={{ fontSize: 16, marginRight: 6, color: isInChain ? "#1A73E8" : "#234A96" }} />
                    {isInChain ? "Exit Layered View" : "Show Layered View"}
                  </div>
                )}

                {(() => {
                  const isCompleted = displayMaturity === "Completed" || displayMaturity === "Released";
                  return (
                    <div
                      style={{
                        padding: 8,
                        display: "flex",
                        alignItems: "center",
                        cursor: isCompleted ? "not-allowed" : "pointer",
                        backgroundColor: hoverIndex === 1 && !isCompleted ? "#bbb8b88a" : "transparent",
                        borderRadius: 4,
                        transition: "background 0.2s ease",
                        borderBottom: "1px solid #ccc",
                        opacity: isCompleted ? 0.5 : 1,
                      }}
                      onMouseEnter={() => !isCompleted && setHoverIndex(1)}
                      onMouseLeave={() => setHoverIndex(null)}
                      onClick={(e) => {
                        if (isCompleted) return;
                        e.stopPropagation();
                        closeMenu();
                        setShowAssigneePopup(true);
                      }}
                    >
                      <PersonIcon style={{ fontSize: 16, marginRight: 6 }} />
                      Change Assignee
                    </div>
                  );
                })()}

                {(() => {
                  const isPromoteDisabled = displayMaturity === "Completed" || displayMaturity === "Released" || subtitle === "Phase";
                  return (
                    <div
                      style={{
                        padding: 8,
                        display: "flex",
                        alignItems: "center",
                        cursor: isPromoteDisabled ? "not-allowed" : "pointer",
                        backgroundColor: hoverIndex === 2 && !isPromoteDisabled ? "#bbb8b88a" : "transparent",
                        borderRadius: 4,
                        transition: "background 0.2s ease",
                        opacity: isPromoteDisabled ? 0.5 : 1,
                      }}
                      onMouseEnter={() => !isPromoteDisabled && setHoverIndex(2)}
                      onMouseLeave={() => setHoverIndex(null)}
                      onClick={(e) => {
                        if (isPromoteDisabled) return;
                        e.stopPropagation();
                        const taskIdToPromote = objectId || id;
                        if (!taskIdToPromote) return;
                        const getNextState = (currentMaturity) => {
                          const s = String(currentMaturity || "").toLowerCase().trim();
                          if (s === "create" || s.includes("draft")) return "Assign";
                          if (s === "assign" || s.includes("to do") || s.includes("todo")) return "Active";
                          if (s === "active" || s.includes("in work") || s.includes("progress")) return "Review";
                          if (s.includes("review")) return "Complete";
                          return "Active";
                        };
                        const nextState = getNextState(maturity);
                        closeMenu();
                        setHoverIndex(null);
                        setTooltip((t) => ({ ...t, visible: false }));

                        if (onPromoteNode) {
                          onPromoteNode(id, taskIdToPromote, nextState, maturity);
                        } else {
                          if (onUpdateNode) onUpdateNode(id, { maturity: nextState });
                          Service.EnoviaService()
                            .promoteTask(taskIdToPromote, nextState)
                            .then(() => {
                              showSuccessToast("Task promoted successfully!");
                              if (!onUpdateNode && onRefresh) onRefresh();
                            })
                            .catch(() => {
                              showErrorToast("Failed to promote task. Reverting state...");
                              if (onUpdateNode) onUpdateNode(id, { maturity: maturity });
                            });
                        }
                      }}
                    >
                      <ArrowUpwardIcon style={{ fontSize: 16, marginRight: 6 }} />
                      Promote
                    </div>
                  );
                })()}
              </div>
            );
          })(),
          document.body
        )}

      {/* ── Subtitle ── aligned to contentLeft */}
      <foreignObject
        x={contentLeft}
        y={subtitleY - iconSize / 2 - 4}
        width={iconSize}
        height={iconSize}
      >
        <div
          xmlns="http://www.w3.org/1999/xhtml"
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            width: "100%",
            height: "100%",
          }}
        >
          {subtitleIcon}
        </div>
      </foreignObject>

      <text
        x={contentLeft + iconSize + 6}
        y={subtitleY - 2}
        fontSize="12"
        fill="#0f0e0eff"
      >
        {subtitle}
      </text>

      {/* Deliverables dots — right side of subtitle row */}
      <DeliverablesDots
        taskId={objectId || id}
        x={contentRight - 60}
        y={subtitleY - 2}
        setTooltip={setTooltip}
        zoomRatio={zoomRatio}
      />

      {/* ── Bottom Row ── all children positioned relative to contentLeft */}
      <g transform={`translate(${contentLeft}, ${rowY})`}>

        {/* Warning icon (only when late/delayed) */}
        {/* {showWarningIcon && (
          <foreignObject
            x={0}
            y={-iconSize / 2 - 1}
            width={iconSize}
            height={iconSize}
            onMouseEnter={() => {
              const tooltipNode = <><strong>Status:</strong> Late</>;
              showLocalTooltip("Status: Late", tooltipNode);
            }}
            onMouseLeave={hideLocalTooltip}
          >
            <div
              xmlns="http://www.w3.org/1999/xhtml"
              style={{ display: "flex", alignItems: "center", justifyContent: "center", width: "100%", height: "100%" }}
            >
              <WarningIcon style={{ fontSize: iconSize, color: "#D9534F" }} />
            </div>
          </foreignObject>
        )} */}

        {/* Due date text */}
        <text x={0} y={-6} fontSize="8" fill="#999" fontWeight="600" letterSpacing="0.5" fontFamily="Arial, sans-serif">DUE DATE</text>
        <text
          x={0}
          y={7}
          fontSize="12"
          fill="#333"
          fontFamily="Arial, sans-serif"
        >
          {dueDate}
        </text>

        {/* Assignee circle — sits just left of the status pill */}
        <g
          transform={`translate(${contentWidth - statusWidth - spacing - assigneeR - spacing + 6}, 0)`}
          onMouseEnter={() => {
            const displayAssignee =
              Array.isArray(d) && d.length > 0
                ? d.join(", ")
                : d && typeof d === "string" && d.trim()
                  ? d
                  : "No Assignee";
            const tooltipNode = <><strong>Assignee:</strong> {displayAssignee}</>;
            showLocalTooltip(`Assignee: ${displayAssignee}`, tooltipNode);
          }}
          onMouseLeave={hideLocalTooltip}
          style={{ cursor: "default" }}
        >
          {isMultipleAssignees ? (
            <foreignObject
              x={-assigneeR}
              y={-assigneeR}
              width={assigneeR * 2}
              height={assigneeR * 2}
            >
              <div
                xmlns="http://www.w3.org/1999/xhtml"
                style={{
                  width: assigneeR * 2,
                  height: assigneeR * 2,
                  borderRadius: "50%",
                  backgroundColor: "#075985",
                  display: "flex",
                  justifyContent: "center",
                  alignItems: "center",
                }}
              >
                <GroupIcon style={{ fontSize: iconSize, color: "#fff" }} />
              </div>
            </foreignObject>
          ) : (
            <>
              <circle r={assigneeR} fill={assigneeColor} />
              {assigneeInitials && (
                <text x="0" y="4" fontSize="12" textAnchor="middle" fill="white" fontWeight="600" fontFamily="Arial, sans-serif">
                  {assigneeInitials}
                </text>
              )}
            </>
          )}
        </g>

        {/* Maturity status pill — right-aligned to content area */}
        <g
          transform={`translate(${contentWidth - statusWidth}, ${-statusHeight / 2 - 1})`}
          onMouseEnter={() => {
            const tooltipString = `Maturity: ${displayMaturity || "—"}\n${maturityDescription || ""}`;
            const tooltipNode = (
              <>
                <strong>Maturity:</strong> {displayMaturity || "—"} <br />
                {maturityDescription && (
                  <><strong>Maturity Description:</strong> {maturityDescription}<br /></>
                )}
              </>
            );
            showLocalTooltip(tooltipString, tooltipNode);
          }}
          onMouseLeave={hideLocalTooltip}
        >
          <rect
            width={statusWidth}
            height={statusHeight}
            rx={10}
            fill={maturityColor}
            stroke={maturityColor === "#FFFFFF" ? "#C8C6B8" : "none"}
            strokeWidth={1}
          />
          <text
            x={statusWidth / 2}
            y={statusHeight / 2 + 1}
            fontSize="12"
            fontWeight="600"
            fill={maturityColor === "#FFFFFF" ? "#333333" : "white"}
            textAnchor="middle"
            dominantBaseline="middle"
            fontFamily="Arial, sans-serif"
          >
            {displayMaturity}
          </text>
        </g>
      </g>

      {/* ── Tooltip ── */}
      {!isThisDropdownOpen && !showAssigneePopup && tooltip.visible &&
        createPortal(
          (() => {
            const nodeRect = nodeRef.current?.getBoundingClientRect() || { top: 0, left: 0, bottom: 0, right: 0 };
            const vw = window.innerWidth;
            const vh = window.innerHeight;
            const MARGIN = 8;
            const spaceBelow = vh - nodeRect.bottom;
            const tooltipTop = spaceBelow < tooltip.height + MARGIN
              ? Math.max(MARGIN, nodeRect.top - tooltip.height - 4)
              : nodeRect.bottom + 4;
            const rawLeft = nodeRect.right - tooltip.width;
            const tooltipLeft = Math.max(MARGIN, Math.min(rawLeft, vw - tooltip.width - MARGIN));
            return (
              <div
                style={{
                  position: "fixed",
                  top: tooltipTop,
                  left: tooltipLeft,
                  minWidth: tooltip.width,
                  background: "white",
                  border: "1px solid #363a3fff",
                  borderRadius: "8px",
                  padding: "8px",
                  fontSize: "12px",
                  color: "#202124",
                  whiteSpace: "pre-line",
                  boxShadow: "0 4px 12px rgba(0,0,0,0.15)",
                  pointerEvents: "none",
                  zIndex: 999999999,
                  lineHeight: "1.6",
                }}
              >
                {tooltip.textNode}
              </div>
            );
          })(),
          document.body
        )}

      {showAssigneePopup && (
        <AssigneePopup
          taskId={objectId || id}
          projectId={projectId}
          taskName={title}
          onClose={() => setShowAssigneePopup(false)}
          onUpdate={(newAssignees) => {
            if (onUpdateNode) onUpdateNode(id, { assignees: newAssignees });
          }}
        />
      )}
    </g>
  );
};

export default ParallelogramNode;